const SHEET_URL =
  'https://opensheet.elk.sh/18ZNQuizNBCEw6Tkvqg7x73n22FT0DnTFmvxE_ZLdtbs/Sheet1';

const useDGProducts = () => {
  const [data, setData] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');

  useEffect(() => {
    const fetchData = async () => {
      try {
        setLoading(true);
        setError('');

        const res = await fetch(SHEET_URL);
        const json = await res.json();

        const formatted = json
          .filter((row) => row.productName && row.bottleSizeLabel)
          .map((row, index) => ({
            id: row.id || `${row.productName}-${row.bottleSizeLabel}-${index}`,
            baseProductId: row.tradeName || row.productName,
            baseProductName: row.tradeName || row.productName,
            productName: row.productName,
            technicalName: row.technicalName || '',
            tradeName: row.tradeName || row.productName || '',
            unNumber: String(row.unNumber || '').trim(),
            dgClass: String(row.dgClass || '').trim(),
            packingGroup: String(row.packingGroup || '').trim(),
            bottleSizeLabel: String(row.bottleSizeLabel || '').trim(),
            bottleSizeLitres: Number(row.bottleSizeLitres || 0),
            outerPackaging: String(row.outerPackaging || '').trim(),
            hazchem: String(row.hazchem || '').trim(),
          }));

        setData(formatted);
      } catch (e) {
        console.error('Failed to load DG data', e);
        setError(
          'Failed to load DG products. Check the sheet link and tab name.'
        );
      } finally {
        setLoading(false);
      }
    };

    fetchData();
  }, []);

  return { data, loading, error };
};

const createEmptyLine = () => ({
  key: `${Date.now()}-${Math.random()}`,
  baseProductId: '',
  productId: '',
  quantity: '',
  isExpanded: true,
});

const formatNumber = (value) => {
  const num = Number(value);
  if (Number.isNaN(num)) return '';
  return Number.isInteger(num)
    ? String(num)
    : num.toFixed(2).replace(/\.00$/, '');
};

const getTodayAu = () => new Date().toLocaleDateString('en-AU');

