export default function App() {
  const { data: DG_PRODUCTS, loading, error } = useDGProducts();

  const PRODUCT_OPTIONS = useMemo(() => {
    return Array.from(
      new Map(
        DG_PRODUCTS.map((item) => [
          item.baseProductId,
          { id: item.baseProductId, name: item.baseProductName },
        ])
      ).values()
    ).sort((a, b) => a.name.localeCompare(b.name));
  }, [DG_PRODUCTS]);

  const [shipment, setShipment] = useState({
    orderNumber: '',
    consignmentNumber: '',
    consigneeName: '',
    consigneeAddress: '',
    date: getTodayAu(),
    outerPackaging: 'CARTON',
  });

  const [lines, setLines] = useState([createEmptyLine()]);

  const selectedProducts = useMemo(() => {
    const map = {};
    for (const line of lines) {
      map[line.key] =
        DG_PRODUCTS.find((item) => item.id === line.productId) || null;
    }
    return map;
  }, [lines, DG_PRODUCTS]);

  const computedLines = useMemo(() => {
    return lines
      .map((line) => {
        const product = selectedProducts[line.key];
        const quantity = Number(line.quantity || 0);
        const nettAggregateQty = product
          ? quantity * Number(product.bottleSizeLitres || 0)
          : 0;

        return {
          ...line,
          product,
          quantity,
          nettAggregateQty,
        };
      })
      .filter((line) => line.product && line.quantity > 0);
  }, [lines, selectedProducts]);

  const summaryLines = useMemo(() => {
    return computedLines.map((line) => ({
      technicalName: line.product.technicalName,
      tradeName: line.product.tradeName,
      dgClass: line.product.dgClass,
      unNumber: line.product.unNumber,
      packingGroup: line.product.packingGroup,
      totalQtyLitres: line.nettAggregateQty,
      totalItems: line.quantity,
      bottleSizeLabel: line.product.bottleSizeLabel,
      hazchem: line.product.hazchem,
    }));
  }, [computedLines]);

  const updateShipment = (field, value) => {
    setShipment((prev) => ({ ...prev, [field]: value }));
  };

  const updateLine = (key, field, value) => {
    setLines((prev) =>
      prev.map((line) => {
        if (line.key !== key) return line;

        if (field === 'baseProductId') {
          return {
            ...line,
            baseProductId: value,
            productId: '',
          };
        }

        return { ...line, [field]: value };
      })
    );
  };

  const toggleLineExpanded = (key) => {
    setLines((prev) =>
      prev.map((line) =>
        line.key === key ? { ...line, isExpanded: !line.isExpanded } : line
      )
    );
  };

  const addLine = () => {
    setLines((prev) => [
      ...prev.map((line) => ({ ...line, isExpanded: false })),
      createEmptyLine(),
    ]);
  };

  const removeLine = (key) => {
    setLines((prev) => {
      if (prev.length === 1) {
        return [createEmptyLine()];
      }
      return prev.filter((line) => line.key !== key);
    });
  };

  const clearAll = () => {
    setShipment({
      orderNumber: '',
      consignmentNumber: '',
      consigneeName: '',
      consigneeAddress: '',
      date: getTodayAu(),
      outerPackaging: 'CARTON',
    });
    setLines([createEmptyLine()]);
  };

  const handleGenerate = () => {
    if (!shipment.consigneeName.trim()) {
      Alert.alert('Missing consignee', 'Please enter the consignee name.');
      return;
    }

    if (computedLines.length === 0) {
      Alert.alert(
        'No DG lines',
        'Please add at least one DG product and quantity.'
      );
      return;
    }

    Alert.alert(
      'Preview ready',
      'The summary below is ready. Print / Save PDF when you want the paperwork.'
    );
  };

  const handlePrintPdf = () => {
    if (!shipment.consigneeName.trim()) {
      Alert.alert(
        'Missing consignee',
        'Please enter the consignee name before printing.'
      );
      return;
    }

    if (computedLines.length === 0) {
      Alert.alert(
        'No DG lines',
        'Please add at least one DG product with a quantity before printing.'
      );
      return;
    }

    if (typeof window === 'undefined') {
      Alert.alert(
        'Web only',
        'PDF printing works from Snack Web in a browser.'
      );
      return;
    }

    try {
      const html = buildCombinedPrintHtml(computedLines, shipment);
      const printWindow = window.open('', '_blank');

      if (!printWindow) {
        Alert.alert(
          'Pop-up blocked',
          'Allow pop-ups in your browser so the print view can open.'
        );
        return;
      }

      printWindow.document.open();
      printWindow.document.write(html);
      printWindow.document.close();
      printWindow.focus();

      setTimeout(() => {
        printWindow.print();
      }, 500);
    } catch (err) {
      console.error('Print failed', err);
      Alert.alert('Print failed', 'The PDF print view could not be created.');
    }
  };

  if (loading) {
    return (
      <SafeAreaView style={styles.loadingWrap}>
        <Text style={styles.loadingText}>Loading DG products...</Text>
      </SafeAreaView>
    );
  }

  if (error) {
    return (
      <SafeAreaView style={styles.loadingWrap}>
        <Text style={styles.errorText}>{error}</Text>
      </SafeAreaView>
    );
  }

  return (
<SafeAreaView style={styles.page}>
  <ScrollView contentContainerStyle={styles.pageInner}>
        <Text style={styles.title}>DG Paperwork Generator</Text>
        <Text style={styles.subtitle}>
          Pick the product, tap the size, enter the quantity, and let the app do
          the dull bit.
        </Text>

        <View style={styles.card}>
          <Text style={styles.sectionTitle}>Shipment Details</Text>

          <Text style={styles.label}>Order Number</Text>
          <TextInput
            style={styles.input}
            value={shipment.orderNumber}
            onChangeText={(value) => updateShipment('orderNumber', value)}
            placeholder="SO182069"
          />

          <Text style={styles.label}>Consignment Number</Text>
          <TextInput
            style={styles.input}
            value={shipment.consignmentNumber}
            onChangeText={(value) => updateShipment('consignmentNumber', value)}
            placeholder="Consignment reference"
          />

          <Text style={styles.label}>Date</Text>
          <TextInput
            style={styles.input}
            value={shipment.date}
            onChangeText={(value) => updateShipment('date', value)}
            placeholder="DD/MM/YYYY"
          />

          <Text style={styles.label}>Consignee Name</Text>
          <TextInput
            style={styles.input}
            value={shipment.consigneeName}
            onChangeText={(value) => updateShipment('consigneeName', value)}
            placeholder="Customer / consignee"
          />

          <Text style={styles.label}>Consignee Address</Text>
          <TextInput
            style={[styles.input, styles.multilineInput]}
            value={shipment.consigneeAddress}
            onChangeText={(value) => updateShipment('consigneeAddress', value)}
            placeholder="Delivery address"
            multiline
          />

          <Text style={styles.label}>Default Outer Packaging</Text>
          <TextInput
            style={styles.input}
            value={shipment.outerPackaging}
            onChangeText={(value) =>
              updateShipment('outerPackaging', value.toUpperCase())
            }
            placeholder="CARTON"
          />
        </View>

        <View style={styles.card}>
          <View style={styles.rowBetween}>
            <Text style={styles.sectionTitle}>DG Items</Text>
          </View>

          {lines.map((line, index) => {
            const product = selectedProducts[line.key];
            const quantity = Number(line.quantity || 0);
            const nettAggregateQty = product
              ? quantity * Number(product.bottleSizeLitres || 0)
              : 0;

            const sizeOptions = DG_PRODUCTS.filter(
              (item) => item.baseProductId === line.baseProductId
            ).sort(
              (a, b) => Number(a.bottleSizeLitres) - Number(b.bottleSizeLitres)
            );

            return (
              <View key={line.key} style={styles.lineCard}>
                <View style={styles.rowBetween}>
                  <TouchableOpacity
                    style={styles.lineHeaderButton}
                    onPress={() => toggleLineExpanded(line.key)}>
                    <Text style={styles.lineTitle}>
                      DG Line {index + 1}
                      {product ? ` - ${product.tradeName}` : ''}
                      {line.isExpanded ? ' ▲' : ' ▼'}
                    </Text>
                  </TouchableOpacity>

                  <TouchableOpacity onPress={() => removeLine(line.key)}>
                    <Text style={styles.removeText}>Remove</Text>
                  </TouchableOpacity>
                </View>

                {!line.isExpanded && product ? (
                  <Text style={styles.collapsedSummary}>
                    {product.bottleSizeLabel} • Qty {line.quantity || '0'} • UN{' '}
                    {product.unNumber}
                  </Text>
                ) : null}

                {line.isExpanded && (
                  <>
                    <Text style={styles.label}>Select Product</Text>
                    <View style={styles.pickerWrap}>
                      <Picker
                        selectedValue={line.baseProductId}
                        onValueChange={(value) =>
                          updateLine(line.key, 'baseProductId', value)
                        }>
                        <Picker.Item label="Choose a DG product..." value="" />
                        {PRODUCT_OPTIONS.map((item) => (
                          <Picker.Item
                            key={item.id}
                            label={item.name}
                            value={item.id}
                          />
                        ))}
                      </Picker>
                    </View>

                    {line.baseProductId ? (
                      <>
                        <Text style={styles.label}>Select Size</Text>
                        <View style={styles.sizeButtonWrap}>
                          {sizeOptions.map((item) => {
                            const isSelected = line.productId === item.id;
                            return (
                              <TouchableOpacity
                                key={item.id}
                                style={[
                                  styles.sizeButton,
                                  isSelected && styles.sizeButtonSelected,
                                ]}
                                onPress={() =>
                                  updateLine(line.key, 'productId', item.id)
                                }>
                                <Text
                                  style={[
                                    styles.sizeButtonText,
                                    isSelected && styles.sizeButtonTextSelected,
                                  ]}>
                                  {item.bottleSizeLabel}
                                </Text>
                              </TouchableOpacity>
                            );
                          })}
                        </View>
                      </>
                    ) : null}

                    <Text style={styles.label}>
                      Quantity of Bottles / Items
                    </Text>
                    <TextInput
                      style={styles.input}
                      value={line.quantity}
                      onChangeText={(value) =>
                        updateLine(
                          line.key,
                          'quantity',
                          value.replace(/[^0-9.]/g, '')
                        )
                      }
                      placeholder="Enter quantity"
                      keyboardType="numeric"
                    />

                    {product ? (
                      <View style={styles.detailsBox}>
                        <Text style={styles.detailText}>
                          <Text style={styles.detailLabel}>
                            Technical Name:
                          </Text>{' '}
                          {product.technicalName}
                        </Text>
                        <Text style={styles.detailText}>
                          <Text style={styles.detailLabel}>Trade Name:</Text>{' '}
                          {product.tradeName}
                        </Text>
                        <Text style={styles.detailText}>
                          <Text style={styles.detailLabel}>UN Number:</Text>{' '}
                          {product.unNumber}
                        </Text>
                        <Text style={styles.detailText}>
                          <Text style={styles.detailLabel}>DG Class:</Text>{' '}
                          {product.dgClass}
                        </Text>
                        <Text style={styles.detailText}>
                          <Text style={styles.detailLabel}>Packing Group:</Text>{' '}
                          {product.packingGroup}
                        </Text>
                        <Text style={styles.detailText}>
                          <Text style={styles.detailLabel}>Bottle Size:</Text>{' '}
                          {product.bottleSizeLabel}
                        </Text>
                        <Text style={styles.detailText}>
                          <Text style={styles.detailLabel}>Hazchem:</Text>{' '}
                          {product.hazchem}
                        </Text>
                        <Text style={styles.detailText}>
                          <Text style={styles.detailLabel}>
                            Outer Packaging:
                          </Text>{' '}
                          {product.outerPackaging}
                        </Text>
                        <Text style={styles.detailText}>
                          <Text style={styles.detailLabel}>
                            Nett Aggregate Qty:
                          </Text>{' '}
                          {formatNumber(nettAggregateQty)} L
                        </Text>
                      </View>
                    ) : null}

                    {index === lines.length - 1 && (
                      <TouchableOpacity
                        style={styles.addInlineButton}
                        onPress={addLine}>
                        <Text style={styles.addInlineButtonText}>
                          + Add Next Line
                        </Text>
                      </TouchableOpacity>
                    )}
                  </>
                )}
              </View>
            );
          })}

          <View style={styles.actionRow}>
            <TouchableOpacity style={styles.secondaryButton} onPress={clearAll}>
              <Text style={styles.secondaryButtonText}>Clear</Text>
            </TouchableOpacity>
            <TouchableOpacity
              style={styles.primaryButton}
              onPress={handleGenerate}>
              <Text style={styles.primaryButtonText}>Generate Preview</Text>
            </TouchableOpacity>
          </View>

          <TouchableOpacity
            style={styles.exportButton}
            onPress={handlePrintPdf}>
            <Text style={styles.exportButtonText}>Print / Save PDF</Text>
          </TouchableOpacity>
        </View>

        <View style={styles.card}>
          <Text style={styles.sectionTitle}>Shipping Form Preview</Text>
          <Text style={styles.previewLine}>
            <Text style={styles.detailLabel}>Consignee:</Text>{' '}
            {shipment.consigneeName || '-'}
          </Text>
          <Text style={styles.previewLine}>
            <Text style={styles.detailLabel}>Address:</Text>{' '}
            {shipment.consigneeAddress || '-'}
          </Text>
          <Text style={styles.previewLine}>
            <Text style={styles.detailLabel}>Consignment No.:</Text>{' '}
            {shipment.consignmentNumber || shipment.orderNumber || '-'}
          </Text>
          <Text style={styles.previewLine}>
            <Text style={styles.detailLabel}>Date:</Text> {shipment.date || '-'}
          </Text>

          <View style={styles.previewTableHeader}>
            <Text style={[styles.previewHeaderCell, styles.cellLarge]}>
              Technical Name
            </Text>
            <Text style={[styles.previewHeaderCell, styles.cellMedium]}>
              Trade/Common
            </Text>
            <Text style={styles.previewHeaderCell}>Class</Text>
            <Text style={styles.previewHeaderCell}>UN</Text>
            <Text style={styles.previewHeaderCell}>PG</Text>
            <Text style={styles.previewHeaderCell}>Qty</Text>
            <Text style={styles.previewHeaderCell}>Items</Text>
          </View>

          {summaryLines.length === 0 ? (
            <Text style={styles.emptyState}>No DG lines added yet.</Text>
          ) : (
            summaryLines.map((row, idx) => (
              <View
                key={`${row.unNumber}-${idx}`}
                style={styles.previewTableRow}>
                <Text style={[styles.previewCell, styles.cellLarge]}>
                  {row.technicalName}
                </Text>
                <Text style={[styles.previewCell, styles.cellMedium]}>
                  {row.tradeName} ({row.bottleSizeLabel})
                </Text>
                <Text style={styles.previewCell}>{row.dgClass}</Text>
                <Text style={styles.previewCell}>{row.unNumber}</Text>
                <Text style={styles.previewCell}>{row.packingGroup}</Text>
                <Text style={styles.previewCell}>
                  {formatNumber(row.totalQtyLitres)} L
                </Text>
                <Text style={styles.previewCell}>
                  {formatNumber(row.totalItems)}
                </Text>
              </View>
            ))
          )}
        </View>

        <View style={styles.card}>
          <Text style={styles.sectionTitle}>Emergency Procedure Preview</Text>
          {computedLines.length === 0 ? (
            <Text style={styles.emptyState}>
              Add a DG line to preview emergency details.
            </Text>
          ) : (
            computedLines.map((line) => (
              <View key={`em-${line.key}`} style={styles.emergencyBox}>
                <Text style={styles.detailText}>
                  <Text style={styles.detailLabel}>Name:</Text>{' '}
                  {line.product.tradeName}
                </Text>
                <Text style={styles.detailText}>
                  <Text style={styles.detailLabel}>UN No.:</Text>{' '}
                  {line.product.unNumber}
                </Text>
                <Text style={styles.detailText}>
                  <Text style={styles.detailLabel}>Hazchem:</Text>{' '}
                  {line.product.hazchem}
                </Text>
              </View>
            ))
          )}
        </View>
      </ScrollView>
    </SafeAreaView>
  );
}

